mapper.select:
SELECT EXISTS (
  SELECT 1
  FROM ticket_orders
  WHERE event_id = #{eventId}
    AND user_id = #{userId}
    AND status = 'succeeded'
)

mapper.update:
UPDATE payments
SET status = 'succeeded',
    updated_at = NOW()
WHERE order_id = #{orderId}
  AND provider_payment_id = #{providerPaymentId}
